import './Design.css';
import IMG from './IMG.jpg';
import Home from './Frame/Home';


function Navbar() {
  return (
    <div>
      <ul className='header'>
        <li>Home</li>
        <li>About</li>
        <li>Project</li>
        <li>Contact</li>
      </ul>
      <Home/>
    </div>
  );
}

export default Navbar;
